using System;using System.Collections.Generic;using System.Linq;class A{static Dictionary<int,List<int>>g=new();static Dictionary<int,int>m=new();static int f(int u){if(m.ContainsKey(u))return m[u];int r=0;if(g.ContainsKey(u))foreach(var v in g[u])r=Math.Max(r,f(v));return m[u]=r+1;}static void Main(){int n=int.Parse(Console.ReadLine());var P=new HashSet<int>();for(;n-->0;){var p=Console.ReadLine().Split(' ');int x=int.Parse(p[0]),y=int.Parse(p[1]);if(!g.ContainsKey(x))g[x]=new();g[x].Add(y);P.Add(x);P.Add(y);}Console.Write(P.Max(f));}}